#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>

#define N 100
#define V 100

int T, N, V, i, j, k, x, y, ans, cnt, flag;

struct point {
    int x, y;
} p[N * V];

struct polygon {
    int n, id;
    struct point *v;
} a[N];

int cmp(const void *a, const void *b) {
    return (a->x - b->x) ? (a->x - b->x) : (a->y - b->y);
}

int in(int i, int j, int k, int l) {
    return (p[i].x - p[j].x) * (p[k].y - p[j].y) - (p[i].y - p[j].y) * (p[k].x - p[j].x) >= 0;
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d", &a[i].n);
            a[i].v = (struct point *)malloc(a[i].n * sizeof(struct point));
            for (j = 0; j < a[i].n; j++) {
                scanf("%d %d", &a[i].v[j].x, &a[i].v[j].y);
            }
            a[i].id = i;
        }
        qsort(p, N * V, sizeof(struct point), cmp);
        for (i = 0; i < N * V; i++) {
            for (j = 0; j < N; j++) {
                flag = 0;
                for (k = 0; k < a[j].n; k++) {
                    if (in(i, a[j].v[k].x, a[j].v[(k + 1) % a[j].n].x, a[j].v[(k + 2) % a[j].n].x)) {
                        flag = 1;
                        break;
                    }
                }
                if (!flag) {
                    ans++;
                    break;
                }
            }
        }
        printf("%d\n", ans);
        for (i = 0; i < N; i++) {
            free(a[i].v);
        }
    }
    return 0;
}

