        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int V = 0;
            int i, j, k, x, y, ans = 0, cnt = 0, flag;
            int[][] p = new int[N * 100][2];
            int[][] a = new int[N][100];

            for (i = 0; i < N; i++) {
                int n = sc.nextInt();
                for (j = 0; j < n; j++) {
                    a[i][j] = sc.nextInt();
                }
                V += n;
            }

            int[] points = new int[N * V];
            int[] pointsIndex = new int[N * V];
            int pointsIndexCount = 0;

            for (i = 0; i < N; i++) {
                for (j = 0; j < a[i].length; j++) {
                    points[pointsIndexCount] = a[i][j];
                    pointsIndex[pointsIndexCount] = i;
                    pointsIndexCount++;
                }
            }

            java.util.Arrays.sort(points, 0, pointsIndexCount);

            for (i = 0; i < pointsIndexCount; i++) {
                for (j = 0; j < N; j++) {
                    flag = 0;
                    for (k = 0; k < a[j].length; k++) {
                        if (in(i, a[j][k], (k + 1) % a[j].length, (k + 2) % a[j].length)) {
                            flag = 1;
                            break;
                        }
                    }
                    if (!flag) {
                        ans++;
                        break;
                    }
                }
            }

            System.out.println(ans);
        }
    }

